     1→import * as oidc from "openid-client";
     2→import { type Request, type Response, type NextFunction } from "express";
     3→import type { AuthUser } from "@workspace/api-zod";
     4→import {
     5→  clearSession,
     6→  getOidcConfig,
     7→  getSessionId,
     8→  getSession,
     9→  updateSession,
    10→  isReplitOidcEnabled,
    11→  type SessionData,
    12→} from "../lib/auth";
    13→
    14→declare global {
    15→  namespace Express {
    16→    interface User extends AuthUser {}
    17→
    18→    interface Request {
    19→      isAuthenticated(): this is AuthedRequest;
    20→      user?: User | undefined;
    21→    }
    22→
    23→    export interface AuthedRequest {
    24→      user: User;
    25→    }
    26→  }
    27→}
    28→
    29→// Per-session in-flight refresh promises to prevent race conditions
    30→// when multiple concurrent requests arrive with an expired token.
    31→const refreshInFlight = new Map<string, Promise<SessionData | null>>();
    32→
    33→async function refreshIfExpired(
    34→  sid: string,
    35→  session: SessionData,
    36→): Promise<SessionData | null> {
    37→  const now = Math.floor(Date.now() / 1000);
    38→  if (!session.expires_at || now <= session.expires_at) return session;
    39→
    40→  if (!session.refresh_token) return null;
    41→
    42→  if (!isReplitOidcEnabled()) {
    43→    return session;
    44→  }
    45→
    46→  // If a refresh is already in progress for this session, wait for it
    47→  // instead of starting a second one (which would invalidate the first
    48→  // refresh_token and log the user out).
    49→  const inflight = refreshInFlight.get(sid);
    50→  if (inflight) return inflight;
    51→
    52→  const refreshPromise = (async (): Promise<SessionData | null> => {
    53→    try {
    54→      const config = await getOidcConfig();
    55→      const tokens = await oidc.refreshTokenGrant(
    56→        config,
    57→        session.refresh_token!,
    58→      );
    59→      session.access_token = tokens.access_token;
    60→      session.refresh_token = tokens.refresh_token ?? session.refresh_token;
    61→      session.expires_at = tokens.expiresIn()
    62→        ? now + tokens.expiresIn()!
    63→        : session.expires_at;
    64→      await updateSession(sid, session);
    65→      return session;
    66→    } catch {
    67→      return null;
    68→    } finally {
    69→      refreshInFlight.delete(sid);
    70→    }
    71→  })();
    72→
    73→  refreshInFlight.set(sid, refreshPromise);
    74→  return refreshPromise;
    75→}
    76→
    77→export async function authMiddleware(
    78→  req: Request,
    79→  res: Response,
    80→  next: NextFunction,
    81→) {
    82→  req.isAuthenticated = function (this: Request) {
    83→    return this.user != null;
    84→  } as Request["isAuthenticated"];
    85→
    86→  const sid = getSessionId(req);
    87→  if (!sid) {
    88→    next();
    89→    return;
    90→  }
    91→
    92→  const session = await getSession(sid);
    93→  if (!session?.user?.id) {
    94→    await clearSession(res, sid);
    95→    next();
    96→    return;
    97→  }
    98→
    99→  const refreshed = await refreshIfExpired(sid, session);
   100→  if (!refreshed) {
   101→    await clearSession(res, sid);
   102→    next();
   103→    return;
   104→  }
   105→
   106→  req.user = refreshed.user;
   107→  next();
   108→}
