     1→import * as client from "openid-client";
     2→import crypto from "crypto";
     3→import { type Request, type Response } from "express";
     4→import { db, sessionsTable } from "@workspace/db";
     5→import { eq } from "drizzle-orm";
     6→import type { AuthUser } from "@workspace/api-zod";
     7→
     8→export const ISSUER_URL = process.env.ISSUER_URL ?? "https://replit.com/oidc";
     9→export const SESSION_COOKIE = "sid";
    10→export const SESSION_TTL = 7 * 24 * 60 * 60 * 1000;
    11→
    12→export interface SessionData {
    13→  user: AuthUser;
    14→  access_token: string;
    15→  refresh_token?: string;
    16→  expires_at?: number;
    17→}
    18→
    19→/**
    20→ * Returns true only when running inside a real Replit environment.
    21→ * Local dev sets REPL_ID=local-dev to satisfy env-var checks without
    22→ * triggering OIDC discovery against replit.com/oidc.
    23→ */
    24→export function isReplitOidcEnabled(): boolean {
    25→  const id = process.env.REPL_ID;
    26→  return !!id && id !== "local-dev";
    27→}
    28→
    29→let oidcConfig: client.Configuration | null = null;
    30→
    31→export async function getOidcConfig(): Promise<client.Configuration> {
    32→  if (!isReplitOidcEnabled()) {
    33→    throw new Error("Replit OIDC not available in this environment (REPL_ID=local-dev or unset). Use Google OAuth or /api/auth/dev-login instead.");
    34→  }
    35→  if (!oidcConfig) {
    36→    oidcConfig = await client.discovery(
    37→      new URL(ISSUER_URL),
    38→      process.env.REPL_ID!,
    39→    );
    40→  }
    41→  return oidcConfig;
    42→}
    43→
    44→export async function createSession(data: SessionData): Promise<string> {
    45→  const sid = crypto.randomBytes(32).toString("hex");
    46→  await db.insert(sessionsTable).values({
    47→    sid,
    48→    sess: data as unknown as Record<string, unknown>,
    49→    expire: new Date(Date.now() + SESSION_TTL),
    50→  });
    51→  return sid;
    52→}
    53→
    54→export async function getSession(sid: string): Promise<SessionData | null> {
    55→  const [row] = await db
    56→    .select()
    57→    .from(sessionsTable)
    58→    .where(eq(sessionsTable.sid, sid));
    59→
    60→  if (!row || row.expire < new Date()) {
    61→    if (row) await deleteSession(sid);
    62→    return null;
    63→  }
    64→
    65→  return row.sess as unknown as SessionData;
    66→}
    67→
    68→export async function updateSession(
    69→  sid: string,
    70→  data: SessionData,
    71→): Promise<void> {
    72→  await db
    73→    .update(sessionsTable)
    74→    .set({
    75→      sess: data as unknown as Record<string, unknown>,
    76→      expire: new Date(Date.now() + SESSION_TTL),
    77→    })
    78→    .where(eq(sessionsTable.sid, sid));
    79→}
    80→
    81→export async function deleteSession(sid: string): Promise<void> {
    82→  await db.delete(sessionsTable).where(eq(sessionsTable.sid, sid));
    83→}
    84→
    85→export async function clearSession(
    86→  res: Response,
    87→  sid?: string,
    88→): Promise<void> {
    89→  if (sid) await deleteSession(sid);
    90→  res.clearCookie(SESSION_COOKIE, { path: "/" });
    91→}
    92→
    93→export function getSessionId(req: Request): string | undefined {
    94→  const authHeader = req.headers["authorization"];
    95→  if (authHeader?.startsWith("Bearer ")) {
    96→    return authHeader.slice(7);
    97→  }
    98→  return req.cookies?.[SESSION_COOKIE];
    99→}
